<template>
  <div class="interaction-page page">
    <h1 class="page-title animate__animated animate__fadeInDown">你的参与很重要</h1>
    <p class="page-subtitle animate__animated animate__fadeIn animate__delay-1s">
      让我们一起成为榄雕传承的一部分
    </p>

    <!-- 互动1：参与方式选择 -->
    <div class="interaction-section animate__animated animate__fadeInUp animate__delay-1s">
      <h2 class="section-title">
        <i class="el-icon-star-on"></i>
        我想参与的方式
      </h2>
      
      <div class="participation-options">
        <div
          v-for="option in participationOptions"
          :key="option.id"
          class="option-card"
          :class="{ selected: selectedOptions.includes(option.id) }"
          @click="toggleOption(option.id)"
        >
          <div class="option-icon">{{ option.icon }}</div>
          <div class="option-title">{{ option.title }}</div>
          <div class="option-desc">{{ option.desc }}</div>
          <div class="option-check" v-if="selectedOptions.includes(option.id)">
            <i class="el-icon-check"></i>
          </div>
        </div>
      </div>

      <div class="submit-button" v-if="selectedOptions.length > 0">
        <el-button type="primary" size="large" round @click="generateCard">
          生成我的非遗参与卡
          <i class="el-icon-document"></i>
        </el-button>
      </div>
    </div>

    <!-- 参与卡展示 -->
    <transition name="fade">
      <div v-if="showCard" class="participation-card animate__animated animate__zoomIn">
        <div class="card-header">
          <h3>我的非遗参与卡</h3>
          <div class="card-date">{{ currentDate }}</div>
        </div>
        <div class="card-body">
          <div class="card-avatar">👤</div>
          <div class="card-content">
            <p class="card-text">我承诺通过以下方式参与增城榄雕非遗传承：</p>
            <ul class="card-list">
              <li v-for="id in selectedOptions" :key="id">
                {{ getOptionTitle(id) }}
              </li>
            </ul>
          </div>
        </div>
        <div class="card-footer">
          <div class="card-slogan">让非遗活起来，从我做起</div>
          <el-button type="text" @click="saveCard">
            <i class="el-icon-download"></i>
            保存分享
          </el-button>
        </div>
      </div>
    </transition>

    <!-- 互动2：留言墙 -->
    <div class="interaction-section animate__animated animate__fadeInUp animate__delay-2s">
      <h2 class="section-title">
        <i class="el-icon-chat-dot-round"></i>
        给榄雕的一句话
      </h2>

      <div class="message-input-area">
        <el-input
          type="textarea"
          v-model="userMessage"
          placeholder="说说你对增城榄雕的看法、期待或建议..."
          :rows="4"
          maxlength="200"
          show-word-limit
        ></el-input>
        <el-button
          type="primary"
          round
          @click="submitMessage"
          :disabled="!userMessage.trim()"
          style="margin-top: 15px;"
        >
          <i class="el-icon-s-promotion"></i>
          发送留言
        </el-button>
      </div>

      <!-- 留言墙 -->
      <div class="message-wall">
        <h3>青年心声墙</h3>
        <div class="messages-grid">
          <div
            v-for="(msg, index) in displayMessages"
            :key="index"
            class="message-item animate__animated animate__fadeIn"
          >
            <div class="message-avatar">{{ msg.avatar }}</div>
            <div class="message-content">
              <p>{{ msg.content }}</p>
              <div class="message-meta">
                <span class="message-author">{{ msg.author }}</span>
                <span class="message-time">{{ msg.time }}</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- 资源入口 -->
    <div class="resources-section animate__animated animate__fadeInUp animate__delay-3s">
      <h2 class="section-title">
        <i class="el-icon-link"></i>
        参与资源
      </h2>

      <div class="resources-grid">
        <div class="resource-card">
          <div class="resource-icon">🏛️</div>
          <h4>工作室探访</h4>
          <p>预约参观周老师的榄雕工作室</p>
          <el-button type="text" @click="showContact">
            预约探访 <i class="el-icon-arrow-right"></i>
          </el-button>
        </div>

        <div class="resource-card">
          <div class="resource-icon">📚</div>
          <h4>体验课程</h4>
          <p>报名参加榄雕体验课程</p>
          <el-button type="text" @click="showContact">
            课程报名 <i class="el-icon-arrow-right"></i>
          </el-button>
        </div>

        <div class="resource-card">
          <div class="resource-icon">🎁</div>
          <h4>体验盲盒</h4>
          <p>88元入门套装预售</p>
          <el-button type="text" @click="showContact">
            立即预购 <i class="el-icon-arrow-right"></i>
          </el-button>
        </div>

        <div class="resource-card">
          <div class="resource-icon">🏆</div>
          <h4>设计大赛</h4>
          <p>参与文创设计赛投稿</p>
          <el-button type="text" @click="showContact">
            了解详情 <i class="el-icon-arrow-right"></i>
          </el-button>
        </div>
      </div>
    </div>

    <!-- 继续按钮 -->
    <div class="continue-button">
      <el-button type="primary" size="large" round @click="nextPage">
        查看结语
        <i class="el-icon-arrow-right"></i>
      </el-button>
    </div>
  </div>
</template>

<script>
export default {
  name: 'InteractionPage',
  data() {
    return {
      participationOptions: [
        { id: 1, icon: '📱', title: '社媒转发', desc: '分享榄雕相关内容' },
        { id: 2, icon: '🎁', title: '购买盲盒', desc: '支持非遗文创产品' },
        { id: 3, icon: '📚', title: '参加体验课', desc: '亲身感受榄雕魅力' },
        { id: 4, icon: '🎨', title: '设计投稿', desc: '参与文创设计大赛' },
        { id: 5, icon: '🎬', title: '内容创作', desc: '制作榄雕相关视频' },
        { id: 6, icon: '👥', title: '推荐朋友', desc: '邀请更多人了解' }
      ],
      selectedOptions: [],
      showCard: false,
      currentDate: '',
      userMessage: '',
      displayMessages: [
        { avatar: '😊', author: '小明', content: '第一次知道榄雕这么精致，想去体验一下！', time: '2分钟前' },
        { avatar: '🌟', author: '小红', content: '传统文化需要我们年轻人的关注和传承', time: '5分钟前' },
        { avatar: '💡', author: '阿强', content: '希望能有更多创意设计，让榄雕走进生活', time: '10分钟前' },
        { avatar: '🎨', author: '小美', content: '88元的盲盒很有吸引力，想买来试试', time: '15分钟前' },
        { avatar: '📱', author: '大伟', content: '已经转发到朋友圈了，让更多人看到', time: '20分钟前' },
        { avatar: '✨', author: '小李', content: '增城本地人表示很自豪，要好好了解家乡文化', time: '25分钟前' }
      ]
    }
  },
  mounted() {
    this.currentDate = new Date().toLocaleDateString('zh-CN')
  },
  methods: {
    toggleOption(id) {
      const index = this.selectedOptions.indexOf(id)
      if (index > -1) {
        this.selectedOptions.splice(index, 1)
      } else {
        this.selectedOptions.push(id)
      }
    },
    getOptionTitle(id) {
      const option = this.participationOptions.find(opt => opt.id === id)
      return option ? option.title : ''
    },
    generateCard() {
      if (this.selectedOptions.length === 0) {
        this.$message.warning('请至少选择一种参与方式')
        return
      }
      this.showCard = true
      this.$message.success('参与卡生成成功！')
    },
    saveCard() {
      this.$message.success('参与卡已保存，可以分享给朋友啦！')
    },
    submitMessage() {
      if (!this.userMessage.trim()) {
        return
      }
      
      const newMessage = {
        avatar: '👤',
        author: '我',
        content: this.userMessage,
        time: '刚刚'
      }
      
      this.displayMessages.unshift(newMessage)
      this.$message.success('留言发送成功！')
      this.userMessage = ''
    },
    showContact() {
      this.$alert('联系方式：请关注"广州非遗"官方平台获取最新信息', '提示', {
        confirmButtonText: '知道了'
      })
    },
    nextPage() {
      this.$router.push('/ending')
    }
  }
}
</script>

<style scoped>
.interaction-page {
  background: #f8f9fa;
  padding-bottom: 60px;
}

.interaction-section {
  background: #fff;
  border-radius: 16px;
  padding: 25px;
  margin-bottom: 30px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
}

.section-title {
  font-size: 22px;
  color: #333;
  margin-bottom: 25px;
  display: flex;
  align-items: center;
  gap: 10px;
  padding-bottom: 15px;
  border-bottom: 2px solid #f0f0f0;
}

.section-title i {
  color: #8B4513;
  font-size: 24px;
}

/* 参与选项 */
.participation-options {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 20px;
  margin-bottom: 25px;
}

.option-card {
  position: relative;
  background: #f8f9fa;
  border: 2px solid #e0e0e0;
  border-radius: 12px;
  padding: 25px 20px;
  text-align: center;
  cursor: pointer;
  transition: all 0.3s ease;
}

.option-card:hover {
  border-color: #8B4513;
  background: #FFF8DC;
  transform: translateY(-3px);
}

.option-card.selected {
  border-color: #8B4513;
  background: linear-gradient(135deg, #FFF8DC, #FAEBD7);
  box-shadow: 0 4px 12px rgba(139, 69, 19, 0.2);
}

.option-icon {
  font-size: 48px;
  margin-bottom: 15px;
}

.option-title {
  font-size: 18px;
  font-weight: bold;
  color: #333;
  margin-bottom: 8px;
}

.option-desc {
  font-size: 13px;
  color: #666;
}

.option-check {
  position: absolute;
  top: 10px;
  right: 10px;
  width: 30px;
  height: 30px;
  background: #67C23A;
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  color: #fff;
  font-size: 18px;
}

.submit-button {
  text-align: center;
  margin-top: 25px;
}

/* 参与卡 */
.participation-card {
  background: linear-gradient(135deg, #8B4513, #D2691E);
  color: #fff;
  border-radius: 16px;
  padding: 30px;
  margin: 30px 0;
  box-shadow: 0 8px 24px rgba(139, 69, 19, 0.3);
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 25px;
  padding-bottom: 20px;
  border-bottom: 2px solid rgba(255, 255, 255, 0.3);
}

.card-header h3 {
  font-size: 24px;
  margin: 0;
}

