  transition: all 0.3s ease;
}

.message-item:hover {
  background: #FFF8DC;
  transform: translateX(5px);
}

.message-avatar {
  width: 50px;
  height: 50px;
  background: #fff;
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 28px;
  flex-shrink: 0;
}

.message-content {
  flex: 1;
}

.message-content p {
  font-size: 15px;
  color: #333;
  line-height: 1.6;
  margin-bottom: 10px;
}

.message-meta {
  display: flex;
  gap: 15px;
  font-size: 13px;
  color: #999;
}

.message-author {
  font-weight: bold;
  color: #8B4513;
}

/* 资源区域 */
.resources-section {
  background: #fff;
  border-radius: 16px;
  padding: 25px;
  margin-bottom: 30px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
}

.resources-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 20px;
}

.resource-card {
  background: linear-gradient(135deg, #FFF8DC, #FAEBD7);
  border-radius: 12px;
  padding: 25px 20px;
  text-align: center;
  transition: all 0.3s ease;
}

.resource-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 6px 20px rgba(139, 69, 19, 0.2);
}

.resource-icon {
  font-size: 48px;
  margin-bottom: 15px;
}

.resource-card h4 {
  font-size: 18px;
  color: #333;
  margin-bottom: 10px;
}

.resource-card p {
  font-size: 13px;
  color: #666;
  margin-bottom: 15px;
  line-height: 1.5;
}

/* 继续按钮 */
.continue-button {
  text-align: center;
  margin-top: 30px;
}

.fade-enter-active, .fade-leave-active {
  transition: opacity 0.5s;
}

.fade-enter, .fade-leave-to {
  opacity: 0;
}

@media (max-width: 750px) {
  .participation-options {
    grid-template-columns: repeat(2, 1fr);
  }
  
  .resources-grid {
    grid-template-columns: repeat(2, 1fr);
